module top_module(out, a, b, c, d, e, f, g, h, obf_sel);parameter n = 1;

   output [n-1:0] out;
   input [n-1:0]  a, b, c, d, e, f, g, h;
   input [2:0]    obf_sel;

   assign         out = obf_sel == 3'b000 ? a : 
                        obf_sel == 3'b001 ? b :
                        obf_sel == 3'b010 ? c : 
                        obf_sel == 3'b011 ? d :
                        obf_sel == 3'b100 ? e :
                        obf_sel == 3'b101 ? f :
                        obf_sel == 3'b110 ? g :
                        obf_sel == 3'b111 ? h : 0 ;endmodule
